ding: 3px 9px;\n  border-radius: 8px;\n  letter-spacing: 0.03em;\n}\n.tx-type-badge.tx-debit[_ngcontent-%COMP%] {\n  background: rgba(249, 112, 102, 0.15);\n  color: #f97066;\n}\n.tx-type-badge.tx-credit[_ngcontent-%COMP%] {\n  background: rgba(74, 222, 128, 0.15);\n  color: #4ade80;\n}\n.tx-type-badge.tx-transfert[_ngcontent-%COMP%] {\n  background: rgba(79, 156, 249, 0.15);\n  color: #4f9cf9;\n}\n\n.tx-numero[_ngcontent-%COMP%] {\n  font-size: 12px;\n  font-family: \"Courier New\", monospace;\n  color: var(--accent);\n  flex: 1;\n}\n\n.tx-status[_ngcontent-%COMP%] {\n  font-size: 11px;\n  padding: 2px 8px;\n  border-radius: 6px;\n  font-weight: 500;\n}\n.tx-status.s-Pay\u00E9[_ngcontent-%COMP%] {\n  background: rgba(74, 222, 128, 0.15);\n  color: #4ade80;\n}\n.tx-status.s-En.attente[_ngcontent-%COMP%] {\n  background: rgba(251, 191, 36, 0.15);\n  color: #fbbf24;\n}\n.tx-status.s-Annul\u00E9[_ngcontent-%COMP%] {\n  background: rgba(249, 112, 102, 0.15);\n  color: #f97066;\n}\n\n.tx-body[_ngcontent-%COMP%] {\n  padding: 12px 14px;\n}\n\n.tx-amount[_ngcontent-%COMP%] {\n  font-size: 22px;\n  font-weight: 600;\n  color: var(--text-1);\n  letter-spacing: -0.5px;\n  margin-bottom: 8px;\n}\n\n.tx-devise[_ngcontent-%COMP%] {\n  font-size: 14px;\n  color: var(--text-2);\n  font-weight: 400;\n  margin-left: 4px;\n}\n\n.tx-meta[_ngcontent-%COMP%] {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.tx-meta[_ngcontent-%COMP%]   span[_ngcontent-%COMP%] {\n  font-size: 12px;\n  color: var(--text-2);\n  background: var(--surface2);\n  padding: 3px 8px;\n  border-radius: 6px;\n}\n\n\n\n.typing-dots[_ngcontent-%COMP%] {\n  display: flex;\n  gap: 5px;\n  align-items: center;\n  padding: 6px 0;\n}\n.typing-dots[_ngcontent-%COMP%]   span[_ngcontent-%COMP%] {\n  width: 8px;\n  height: 8px;\n  background: var(--text-3);\n  border-radius: 50%;\n  animation: _ngcontent-%COMP%_dot-bounce 1.3s infinite ease-in-out;\n}\n.typing-dots[_ngcontent-%COMP%]   span[_ngcontent-%COMP%]:nth-child(2) {\n  animation-delay: 0.2s;\n}\n.typing-dots[_ngcontent-%COMP%]   span[_ngcontent-%COMP%]:nth-child(3) {\n  animation-delay: 0.4s;\n}\n\n@keyframes _ngcontent-%COMP%_dot-bounce {\n  0%, 80%, 100% {\n    transform: scale(0.6);\n    opacity: 0.4;\n  }\n  40% {\n    transform: scale(1);\n    opacity: 1;\n  }\n}\n\n\n\n\n.input-zone[_ngcontent-%COMP%] {\n  padding: 16px 24px 12px;\n  background: var(--bg);\n  border-top: 1px solid var(--border);\n  max-width: 760px;\n  width: 100%;\n  margin: 0 auto;\n  padding-bottom: 8px;\n}\n\n\n\n.quick-chips[_ngcontent-%COMP%] {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  margin-bottom: 12px;\n}\n\n.chip[_ngcontent-%COMP%] {\n  font-family: var(--font);\n  font-size: 12px;\n  color: var(--text-2);\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 20px;\n  padding: 6px 12px;\n  cursor: pointer;\n  transition: background 0.12s, color 0.12s, border-color 0.12s;\n  white-space: nowrap;\n}\n.chip[_ngcontent-%COMP%]:hover {\n  background: var(--surface2);\n  color: var(--text-1);\n  border-color: var(--accent);\n}\n.chip[_ngcontent-%COMP%]:disabled {\n  opacity: 0.5;\n  cursor: default;\n}\n\n\n\n.input-box[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: flex-end;\n  gap: 10px;\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 16px;\n  padding: 10px 12px;\n  transition: border-color 0.15s, box-shadow 0.15s;\n}\n.input-box.focused[_ngcontent-%COMP%] {\n  border-color: var(--accent);\n  box-shadow: 0 0 0 3px rgba(79, 156, 249, 0.1);\n}\n\ntextarea[_ngcontent-%COMP%] {\n  flex: 1;\n  background: transparent;\n  border: none;\n  outline: none;\n  color: var(--text-1);\n  font-family: var(--font);\n  font-size: 14px;\n  line-height: 1.6;\n  resize: none;\n  max-height: 180px;\n  overflow-y: auto;\n}\ntextarea[_ngcontent-%COMP%]::placeholder {\n  color: var(--text-3);\n}\ntextarea[_ngcontent-%COMP%]:disabled {\n  opacity: 0.6;\n}\ntextarea[_ngcontent-%COMP%]::-webkit-scrollbar {\n  width: 3px;\n}\ntextarea[_ngcontent-%COMP%]::-webkit-scrollbar-thumb {\n  background: var(--border);\n}\n\n.send-btn[_ngcontent-%COMP%] {\n  width: 36px;\n  height: 36px;\n  border-radius: 10px;\n  border: none;\n  background: var(--surface2);\n  color: var(--text-3);\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: background 0.15s, color 0.15s, transform 0.1s;\n  flex-shrink: 0;\n}\n.send-btn.active[_ngcontent-%COMP%] {\n  background: var(--accent);\n  color: #fff;\n}\n.send-btn.active[_ngcontent-%COMP%]:hover {\n  background: #3b82f6;\n  transform: scale(1.05);\n}\n.send-btn[_ngcontent-%COMP%]:disabled {\n  opacity: 0.5;\n  cursor: default;\n  transform: none;\n}\n\n\n\n.spinner[_ngcontent-%COMP%] {\n  width: 16px;\n  height: 16px;\n  border: 2px solid rgba(255, 255, 255, 0.3);\n  border-top-color: #fff;\n  border-radius: 50%;\n  animation: _ngcontent-%COMP%_spin 0.7s linear infinite;\n}\n\n@keyframes _ngcontent-%COMP%_spin {\n  to {\n    transform: rotate(360deg);\n  }\n}\n.input-note[_ngcontent-%COMP%] {\n  text-align: center;\n  font-size: 11px;\n  color: var(--text-3);\n  margin-top: 8px;\n  line-height: 1.5;\n}\n\n\n\n\n\n@media (max-width: 768px) {\n  .sidebar[_ngcontent-%COMP%] {\n    display: none;\n  }\n  .dwexo-shell.sidebar-open[_ngcontent-%COMP%]   .sidebar[_ngcontent-%COMP%] {\n    display: flex;\n    position: fixed;\n    z-index: 100;\n    height: 100vh;\n    box-shadow: 4px 0 20px rgba(0, 0, 0, 0.5);\n  }\n  .suggestion-grid[_ngcontent-%COMP%] {\n    grid-template-columns: 1fr;\n  }\n  .messages-inner[_ngcontent-%COMP%] {\n    padding: 0 14px;\n  }\n  .input-zone[_ngcontent-%COMP%] {\n    padding: 12px 14px 8px;\n  }\n}\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
